function sahirastha_extract_hero_fields(string $heroText): array
{
    $fields = [
        'headline' => '',
        'subheadline' => '',
        'support_line' => '',
        'primary_cta' => 'Request a Case Review',
        'secondary_cta' => '',
    ];

    foreach (preg_split('/\R+/', trim($heroText)) as $line) {
        $line = trim($line);
        if ($line === '') {
            continue;
        }

        if (str_starts_with($line, 'Page headline:')) {
            $fields['headline'] = trim(substr($line, strlen('Page headline:')));
            continue;
        }

        if (str_starts_with($line, 'Subheadline:')) {
            $fields['subheadline'] = trim(substr($line, strlen('Subheadline:')));
            continue;
        }

        if (str_starts_with($line, 'Support line:')) {
            $fields['support_line'] = trim(substr($line, strlen('Support line:')));
            continue;
        }

        if (str_starts_with($line, 'Primary CTA:')) {
            $fields['primary_cta'] = trim(substr($line, strlen('Primary CTA:')));
            continue;
        }

        if (str_starts_with($line, 'Secondary CTA:')) {
            $fields['secondary_cta'] = trim(substr($line, strlen('Secondary CTA:')));
            continue;
        }
    }

    return $fields;
}

function sahirastha_render_section_text(string $text, bool $isFaq = false): string
{
    $lines = array_values(array_filter(array_map('trim', preg_split('/\R+/', trim($text)))));
    if ($lines === []) {
        return '';
    }

    $html = '';

    if ($isFaq) {
        for ($i = 0; $i < count($lines); $i += 2) {
            $q = $lines[$i] ?? '';
            $a = $lines[$i + 1] ?? '';
            if ($q !== '') {
                $html .= '<h3>' . esc_html($q) . '</h3>';
            }
            if ($a !== '') {
                $html .= '<p>' . esc_html($a) . '</p>';
            }
        }

        return $html;
    }

    $listMode = false;
    foreach ($lines as $line) {
        $looksLikeLead = str_ends_with($line, 'include:') || str_ends_with($line, 'include') || str_ends_with($line, 'documents include:');
        if ($looksLikeLead) {
            if ($listMode) {
                $html .= '</ul>';
                $listMode = false;
            }
            $html .= '<p>' . esc_html($line) . '</p>';
            continue;
        }

        $wordCount = str_word_count($line);
        $isLikelyBullet = $wordCount <= 24;

        if ($isLikelyBullet) {
            if (!$listMode) {
                $html .= '<ul>';
                $listMode = true;
            }
            $html .= '<li>' . esc_html($line) . '</li>';
            continue;
        }

        if ($listMode) {
            $html .= '</ul>';
            $listMode = false;
        }

        $html .= '<p>' . esc_html($line) . '</p>';
    }

    if ($listMode) {
        $html .= '</ul>';
    }

    return $html;
}

function sahirastha_build_insurance_service_content(array $service, array $allServices): string
{
    $sections = $service['sections'] ?? [];
    $hero = sahirastha_extract_hero_fields((string) ($sections['Hero Section'] ?? ''));

    $content = '<div class="sahirastha-service-hero">';
    if ($hero['headline'] !== '') {
        $content .= '<h2>' . esc_html($hero['headline']) . '</h2>';
    }
    if ($hero['subheadline'] !== '') {
        $content .= '<p>' . esc_html($hero['subheadline']) . '</p>';
    }
    if ($hero['support_line'] !== '') {
        $content .= '<p>' . esc_html($hero['support_line']) . '</p>';
    }
    $content .= '<p><strong>' . esc_html($hero['primary_cta']) . '</strong></p>';
    if ($hero['secondary_cta'] !== '') {
        $content .= '<p>' . esc_html($hero['secondary_cta']) . '</p>';
    }
    $content .= '</div>';

    foreach ($sections as $sectionTitle => $sectionBody) {
        if ($sectionTitle === 'Hero Section') {
            continue;
        }

        $content .= '<h2>' . esc_html($sectionTitle) . '</h2>';
        $content .= sahirastha_render_section_text((string) $sectionBody, str_contains($sectionTitle, 'Frequently Asked Questions'));
    }

    $crossLinks = [];
    $keywords = [
        'death claim' => 'insurance-death-claim-support',
        'nominee' => 'insurance-nominee-issues',
        'lost policy' => 'insurance-lost-policy-bond',
        'record mismatch' => 'insurance-old-record-mismatch',
        'bank' => 'insurance-kyc-bank-mismatch-blocking-payout',
        'kyc' => 'insurance-kyc-bank-mismatch-blocking-payout',
        'short-settled' => 'insurance-short-settled-claims',
        'survival benefit' => 'insurance-survival-benefit-not-received',
        'rejected' => 'insurance-rejected-claims',
        'policy loan' => 'insurance-policy-loan-complications',
    ];

    $combined = strtolower(wp_strip_all_tags($content));
    foreach ($keywords as $term => $slug) {
        if ($slug === ($service['slug'] ?? '') || !str_contains($combined, $term)) {
            continue;
        }

        foreach ($allServices as $candidate) {
            if (($candidate['slug'] ?? '') !== $slug) {
                continue;
            }

            $crossLinks[$slug] = [
                'title' => $candidate['title'],
                'url' => home_url('/' . $slug . '/'),
            ];
        }
    }

    if ($crossLinks !== []) {
        $content .= '<h2>Related Insurance Service Routes</h2><div class="sahirastha-service-links"><ul>';
        foreach ($crossLinks as $link) {
            $content .= '<li><a href="' . esc_url($link['url']) . '">' . esc_html($link['title']) . '</a></li>';
        }
        $content .= '</ul></div>';
    }

    return $content;
}

function sahirastha_build_services_page_insurance_section(array $services): string
{
    $content = '<h2>Insurance Claims & Recovery</h2>';
    $content .= '<p>This section covers insurance amounts and claim problems that are stuck, delayed, disputed, or blocked by documentation. Choose the route closest to your issue.</p>';
    $content .= '<ul>';

    foreach ($services as $service) {
        $content .= '<li><a href="' . esc_url(home_url('/' . $service['slug'] . '/')) . '"><strong>' . esc_html($service['title']) . '</strong></a></li>';
    }

    $content .= '</ul>';
    $content .= '<p>If your case overlaps across payout, nominee, record mismatch, missing papers, or family-entitlement issues, request a case review and start with the route that appears closest.</p>';

    return $content;
}
